{
  "name": "VisaScope AI",
  "description": "An intelligent visa status prediction and processing time estimator using Gemini AI to provide data-driven insights for travelers and immigrants.",
  "requestFramePermissions": ["geolocation"]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type VisaType = 'Tourist' | 'Student' | 'Work' | 'Business' | 'Digital Nomad' | 'Permanent Residency';

export interface VisaApplicationData {
  nationality: string;
  destination: string;
  visaType: VisaType;
  employmentStatus: string;
  monthlyIncome: number;
  travelHistory: string;
  purposeOfVisit: string;
  documentsPrepared: string[];
}

export interface PredictionResult {
  approvalProbability: number;
  estimatedDays: number;
  riskLevel: 'Low' | 'Medium' | 'High';
  keyFactors: {
    factor: string;
    impact: 'positive' | 'negative' | 'neutral';
    description: string;
  }[];
  recommendations: string[];
  recentTrends: string;
  sources?: { title: string; uri: string }[];
}

export interface ProcessingTrendData {
  month: string;
  days: number;
  volume: number;
}

import { VisaType } from './types';

export const VISA_TYPES: VisaType[] = [
  'Tourist',
  'Student',
  'Work',
  'Business',
  'Digital Nomad',
  'Permanent Residency'
];

export const COUNTRIES = [
  "United States", "United Kingdom", "Canada", "Australia", "Germany", 
  "France", "Japan", "South Korea", "Singapore", "Schengen Area", 
  "United Arab Emirates", "Thailand", "New Zealand", "Ireland"
];

export const EMPLOYMENT_STATUSES = [
  "Employed Full-Time", "Self-Employed", "Student", "Unemployed", "Retired", "Business Owner"
];

export const SAMPLE_TREND_DATA = [
  { month: 'Jan', days: 15, volume: 400 },
  { month: 'Feb', days: 18, volume: 300 },
  { month: 'Mar', days: 22, volume: 500 },
  { month: 'Apr', days: 25, volume: 700 },
  { month: 'May', days: 20, volume: 600 },
  { month: 'Jun', days: 28, volume: 850 },
];

import { GoogleGenAI, Type } from "@google/genai";
import { VisaApplicationData, PredictionResult } from "../types";

const API_KEY = process.env.API_KEY || "";

export const predictVisaStatus = async (data: VisaApplicationData): Promise<PredictionResult> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  const prompt = `
    Analyze this visa application and predict the approval probability and processing time.
    User Nationality: ${data.nationality}
    Destination: ${data.destination}
    Visa Type: ${data.visaType}
    Employment: ${data.employmentStatus}
    Monthly Income: $${data.monthlyIncome}
    Purpose: ${data.purposeOfVisit}
    Travel History Summary: ${data.travelHistory}
    Documents: ${data.documentsPrepared.join(", ")}

    Use Google Search to find current embassy processing times and recent policy changes for ${data.visaType} visas to ${data.destination}.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            approvalProbability: { type: Type.NUMBER },
            estimatedDays: { type: Type.NUMBER },
            riskLevel: { type: Type.STRING },
            keyFactors: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  factor: { type: Type.STRING },
                  impact: { type: Type.STRING },
                  description: { type: Type.STRING }
                },
                required: ["factor", "impact", "description"]
              }
            },
            recommendations: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            },
            recentTrends: { type: Type.STRING }
          },
          required: ["approvalProbability", "estimatedDays", "riskLevel", "keyFactors", "recommendations", "recentTrends"]
        }
      }
    });

    const result = JSON.parse(response.text) as PredictionResult;

    // Extract sources from grounding metadata if available
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks?.map((chunk: any) => ({
      title: chunk.web?.title || "Reference Source",
      uri: chunk.web?.uri || "#"
    }));

    return { ...result, sources };
  } catch (error) {
    console.error("Error predicting visa status:", error);
    throw error;
  }
};

import React from 'react';
import { PredictionResult } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';
